// Test case that compares a file generated by rust_xlsxwriter with a
// reference file.
//
// Note: unlike most chart tests the input file wasn't created in Excel. It
// was generated by an earlier run of this test code and verified manually.
// It acts as a regression test until an Excel generated reference file is
// available.
//
// SPDX-License-Identifier: MIT OR Apache-2.0
//
// Copyright 2022-2026, John McNamara, jmcnamara@cpan.org

use crate::common;
use rust_xlsxwriter::{Chart, ChartType, Workbook, XlsxError};

// Create a rust_xlsxwriter file to compare against a reference file.
fn create_new_xlsx_file(filename: &str) -> Result<(), XlsxError> {
    let mut workbook = Workbook::new();

    let worksheet = workbook.add_worksheet();

    // Add some test data for the chart(s).
    let data = [[1, 2, 3], [2, 4, 6], [3, 6, 9], [4, 8, 12], [5, 10, 15]];
    for (row_num, row_data) in data.iter().enumerate() {
        for (col_num, col_data) in row_data.iter().enumerate() {
            worksheet.write_number(row_num as u32, col_num as u16, *col_data)?;
        }
    }

    // Add one chart of each 3D chart family.
    let chart_types = [
        ChartType::Column3D,
        ChartType::Bar3DStacked,
        ChartType::Area3D,
        ChartType::Pie3D,
        ChartType::Line3D,
        ChartType::Surface3D,
        ChartType::Contour,
    ];

    for (index, chart_type) in chart_types.iter().enumerate() {
        let mut chart = Chart::new(*chart_type);

        chart
            .add_series()
            .set_categories(("Sheet1", 0, 0, 4, 0))
            .set_values(("Sheet1", 0, 1, 4, 1));

        chart
            .add_series()
            .set_categories(("Sheet1", 0, 0, 4, 0))
            .set_values(("Sheet1", 0, 2, 4, 2));

        worksheet.insert_chart(8 + 16 * index as u32, 4, &chart)?;
    }

    workbook.save(filename)?;

    Ok(())
}

#[test]
fn test_chart_3d01() {
    let test_runner = common::TestRunner::new()
        .set_name("chart_3d01")
        .set_function(create_new_xlsx_file)
        .initialize();

    test_runner.assert_eq();
    test_runner.cleanup();
}
